// Validate outputs exist for each account
const fs = require('fs');
const path = require('path');
const outputsDir = $input.first().json.outputs_dir;
const accounts = fs.readdirSync(outputsDir).filter(f => f.startsWith('ACC'));
const results = [];

for (const account of accounts) {
  const v1Exists = fs.existsSync(path.join(outputsDir, account, 'v1', 'account_memo.json'));
  const v2Exists = fs.existsSync(path.join(outputsDir, account, 'v2', 'account_memo.json'));
  const changelogExists = fs.existsSync(path.join(outputsDir, account, 'changes.json'));

  results.push({
    account_id: account,
    v1_complete: v1Exists,
    v2_complete: v2Exists,
    changelog_exists: changelogExists,
    status: v1Exists && v2Exists ? 'complete' : 'incomplete'
  });
}

return results.map(r => ({ json: r }));

// Generate summary report
const items = $input.all();
const summary = {
  total_accounts: items.length,
  complete: items.filter(i => i.json.status === 'complete').length,
  incomplete: items.filter(i => i.json.status === 'incomplete').length,
  timestamp: new Date().toISOString()
};
return [{ json: summary }];

// Flag incomplete accounts for manual review
const item = $input.first();
return [{
  json: {
    alert: `Account ${item.json.account_id} is incomplete`,
    v1: item.json.v1_complete,
    v2: item.json.v2_complete,
    action: 'manual_review_required'
  }
}];
